# Bit Manipulation Examples

# Single Number
def single_number(nums):
    result = 0
    for num in nums:
        result ^= num
    return result

# Counting Bits
def count_bits(n):
    result = [0] * (n + 1)
    for i in range(1, n + 1):
        result[i] = result[i >> 1] + (i & 1)
    return result

# Power of Two
def is_power_of_two(n):
    return n > 0 and (n & (n - 1)) == 0

# Hamming Weight
def hamming_weight(n):
    count = 0
    while n:
        n &= n - 1
        count += 1
    return count

# Missing Number
def missing_number(nums):
    result = len(nums)
    for i, num in enumerate(nums):
        result ^= i ^ num
    return result

# Reverse Bits
def reverse_bits(n):
    result = 0
    for _ in range(32):
        result = (result << 1) | (n & 1)
        n >>= 1
    return result

# Find Two Unique Numbers
def find_unique(nums):
    xor_all = 0
    for num in nums:
        xor_all ^= num
    diff_bit = xor_all & (-xor_all)
    a, b = 0, 0
    for num in nums:
        if num & diff_bit:
            a ^= num
        else:
            b ^= num
    return [a, b]

# Generate Subsets Using Bitmask
def subsets(nums):
    result = []
    n = len(nums)
    for mask in range(1 << n):
        subset = []
        for i in range(n):
            if mask & (1 << i):
                subset.append(nums[i])
        result.append(subset)
    return result

# Test all functions
if __name__ == "__main__":
    print("Single Number:", single_number([4, 1, 2, 1, 2]))
    print("Count Bits (5):", count_bits(5))
    print("Power of Two:", is_power_of_two(16))
    print("Hamming Weight:", hamming_weight(11))
    print("Missing Number:", missing_number([3, 0, 1]))
    print("Reverse Bits:", reverse_bits(43261596))
    print("Find Unique:", find_unique([1, 2, 1, 3, 2, 5]))
    print("Subsets:", subsets([1, 2, 3]))
